    50→fun PlayerScreen(
    51→    videoPath: String,
    52→    subtitlePath: String?,
    53→    onBack: () -> Unit,
    54→    viewModel: PlayerViewModel = hiltViewModel()
    55→) {
    56→    val uiState by viewModel.uiState.collectAsState()
    57→    val context = LocalContext.current
    58→    val listState = rememberLazyListState()
    59→    val coroutineScope = rememberCoroutineScope()
    60→
    61→    // 注册转录服务广播接收器
    62→    val transcriptionReceiver = remember {
    63→        object : BroadcastReceiver() {
    64→            override fun onReceive(context: Context?, intent: Intent?) {
    65→                when (intent?.action) {
    66→                    TranscriptionService.ACTION_PROGRESS -> {
    67→                        val segment = intent.getIntExtra(TranscriptionService.EXTRA_SEGMENT, 0)
    68→                        val total = intent.getIntExtra(TranscriptionService.EXTRA_TOTAL, 0)
    69→                        val progress = intent.getIntExtra(TranscriptionService.EXTRA_PROGRESS, 0)
    70→                        val message = intent.getStringExtra(TranscriptionService.EXTRA_MESSAGE) ?: ""
    71→                        val remaining = intent.getLongExtra(TranscriptionService.EXTRA_REMAINING, 0)
    72→                        viewModel.onTranscriptionProgress(segment, total, progress, message, remaining)
    73→                    }
    74→                    TranscriptionService.ACTION_COMPLETED -> {
    75→                        val success = intent.getBooleanExtra(TranscriptionService.EXTRA_SUCCESS, false)
    76→                        val detectedLang = intent.getStringExtra(TranscriptionService.EXTRA_DETECTED_LANG) ?: ""
    77→                        val subtitleCount = intent.getIntExtra(TranscriptionService.EXTRA_SUBTITLE_COUNT, 0)
    78→                        val error = intent.getStringExtra(TranscriptionService.EXTRA_ERROR)
    79→                        viewModel.onTranscriptionCompleted(videoPath, success, detectedLang, subtitleCount, error)
    80→                    }
    81→                }
    82→            }
    83→        }
    84→    }
    85→
    86→    // 注册和注销广播接收器
    87→    DisposableEffect(Unit) {
    88→        val progressFilter = IntentFilter(TranscriptionService.ACTION_PROGRESS)
    89→        val completedFilter = IntentFilter(TranscriptionService.ACTION_COMPLETED)
    90→        context.registerReceiver(transcriptionReceiver, progressFilter)
    91→        context.registerReceiver(transcriptionReceiver, completedFilter)
    92→
    93→        onDispose {
    94→            context.unregisterReceiver(transcriptionReceiver)
    95→        }
    96→    }
    97→
    98→    // 绑定转录服务以检查状态
    99→    var serviceBinder: TranscriptionService.LocalBinder? = null
   100→    val serviceConnection = remember {
   101→        object : ServiceConnection {
   102→            override fun onServiceConnected(name: ComponentName?, service: IBinder?) {
   103→                val binder = service as TranscriptionService.LocalBinder
   104→                serviceBinder = binder
   105→                // 获取服务当前状态并同步到 UI
   106→                coroutineScope.launch {
   107→                    binder.getService().serviceState.collect { state ->
   108→                        when (state) {
   109→                            is ServiceState.Transcribing -> {
   110→                                viewModel.syncServiceState(
   111→                                    isServiceTranscribing = true,
   112→                                    segment = state.segment,
   113→                                    total = state.total,
   114→                                    progress = state.progress,
   115→                                    message = state.message,
   116→                                    remaining = 0
   117→                                )
   118→                            }
   119→                            is ServiceState.Idle,
   120→                            is ServiceState.Completed,
   121→                            is ServiceState.Error -> {
   122→                                // 服务不在转录状态，无需同步
   123→                            }
   124→                        }
   125→                    }
   126→                }
   127→            }
   128→
   129→            override fun onServiceDisconnected(name: ComponentName?) {
   130→                serviceBinder = null
   131→            }
   132→        }
   133→    }
   134→
   135→    DisposableEffect(Unit) {
   136→        val intent = Intent(context, TranscriptionService::class.java)
   137→        context.bindService(intent, serviceConnection, Context.BIND_AUTO_CREATE)
   138→
   139→        onDispose {
   140→            serviceBinder?.let { context.unbindService(serviceConnection) }
   141→        }
   142→    }
   143→
   144→    // ExoPlayer
   145→    val exoPlayer = remember {
   146→        ExoPlayer.Builder(context).build().apply {
   147→            setMediaItem(MediaItem.fromUri(videoPath))
   148→            prepare()
   149→        }
   150→    }
   151→
   152→    // Load subtitles
   153→    LaunchedEffect(videoPath) {
   154→        viewModel.loadSubtitles(videoPath, subtitlePath)
   155→    }
   156→
   157→    // 30ms position polling (ported from renderer.js syncTimer)
   158→    LaunchedEffect(exoPlayer) {
   159→        while (isActive) {
   160→            if (exoPlayer.isPlaying) {
   161→                viewModel.updatePosition(exoPlayer.currentPosition)
   162→            }
   163→            delay(30)
   164→        }
   165→    }
   166→
   167→    // Auto-scroll subtitle list
   168→    LaunchedEffect(uiState.currentCueIndex) {
   169→        if (uiState.currentCueIndex >= 0) {
   170→            listState.animateScrollToItem(uiState.currentCueIndex)
   171→        }
   172→    }
   173→
   174→    DisposableEffect(Unit) {
   175→        onDispose { exoPlayer.release() }
   176→    }
   177→
   178→    Scaffold(
   179→        topBar = {
   180→            TopAppBar(
   181→                title = { Text("视频学习") },
   182→                navigationIcon = {
   183→                    IconButton(onClick = { exoPlayer.release(); onBack() }) {
   184→                        Icon(Icons.Default.ArrowBack, "返回")
   185→                    }
   186→                }
   187→            )
   188→        }
   189→    ) { padding ->
   190→        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
   191→            // Video Player
   192→            AndroidView(
   193→                factory = {
   194→                    PlayerView(context).apply {
   195→                        player = exoPlayer
   196→                        layoutParams = FrameLayout.LayoutParams(
   197→                            ViewGroup.LayoutParams.MATCH_PARENT,
   198→                            ViewGroup.LayoutParams.WRAP_CONTENT
   199→                        )
   200→                    }
   201→                },
   202→                modifier = Modifier.fillMaxWidth().heightIn(max = 300.dp)
   203→            )
   204→
   205→            // Mode bar (学习/听写/重新转录)
   206→            Row(
   207→                modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
   208→                horizontalArrangement = Arrangement.spacedBy(8.dp)
   209→            ) {
   210→                FilterChip(
   211→                    selected = uiState.mode == "learn",
   212→                    onClick = { viewModel.setMode("learn") },
