   215→                FilterChip(
   216→                    selected = uiState.mode == "dictation",
   217→                    onClick = { viewModel.setMode("dictation") },
   218→                    label = { Text("听写模式") }
   219→                )
   220→                Spacer(Modifier.weight(1f))
   221→                AssistChip(
   222→                    onClick = { exoPlayer.pause(); viewModel.retranscribe(videoPath) },
   223→                    enabled = !uiState.isTranscribing,
   224→                    label = {
   225→                        if (uiState.isTranscribing) {
   226→                            Row(verticalAlignment = Alignment.CenterVertically) {
   227→                                CircularProgressIndicator(
   228→                                    modifier = Modifier.size(16.dp),
   229→                                    strokeWidth = 2.dp,
   230→                                    color = MaterialTheme.colorScheme.primary
   231→                                )
   232→                                Spacer(Modifier.width(4.dp))
   233→                                Text(when {
   234→                                    uiState.transcribeTotalSegments > 1 ->
   235→                                        "${uiState.transcribeSegment}/${uiState.transcribeTotalSegments}"
   236→                                    else -> "转录中..."
   237→                                })
   238→                            }
   239→                        } else {
   240→                            Text("🔄 重新转录")
   241→                        }
   242→                    }
   243→                )
   244→            }
   245→
   246→            if (uiState.mode == "learn") {
   247→                // === Learning Mode ===
   248→                // Current subtitle with karaoke highlighting
   249→                Card(
   250→                    modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
   251→                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)
   252→                ) {
   253→                    Column(modifier = Modifier.padding(16.dp)) {
   254→                        if (uiState.currentCueIndex >= 0 && uiState.currentCueIndex < uiState.subtitles.size) {
   255→                            val cue = uiState.subtitles[uiState.currentCueIndex]
   256→                            val words = cue.text.split(Regex("\\s+")).filter { it.isNotBlank() }
   257→                            val timings = viewModel.getAlignedTimings(words)
   258→                            val currentSec = uiState.currentPositionMs / 1000.0
   259→
   260→                            // Karaoke-style word-by-word display - clickable for instant lookup
   261→                            val annotatedText = buildAnnotatedString {
   262→                                words.forEachIndexed { i, word ->
   263→                                    val wt = timings.getOrNull(i)
   264→                                    val style = when {
   265→                                        wt != null && currentSec >= wt.s && currentSec < wt.e ->
   266→                                            SpanStyle(color = MaterialTheme.colorScheme.primary, fontWeight = FontWeight.Bold, fontSize = 24.sp)
   267→                                        wt != null && currentSec >= wt.e ->
   268→                                            SpanStyle(color = MaterialTheme.colorScheme.primary.copy(alpha = 0.7f), fontSize = 22.sp)
   269→                                        else -> SpanStyle(color = MaterialTheme.colorScheme.onSurface, fontSize = 22.sp)
   270→                                    }
   271→                                    pushStringAnnotation("word", word.replace(Regex("[^\\p{L}\\p{M}'-]"), ""))
   272→                                    withStyle(style) { append(word) }
   273→                                    pop()
   274→                                    if (i < words.size - 1) append(" ")
   275→                                }
   276→                            }
   277→                            ClickableText(
   278→                                text = annotatedText,
   279→                                modifier = Modifier.fillMaxWidth(),
   280→                                style = TextStyle(textAlign = TextAlign.Center),
   281→                                onClick = { offset ->
   282→                                    annotatedText.getStringAnnotations("word", offset, offset)
   283→                                        .firstOrNull()?.let { annotation ->
   284→                                            val cleanWord = annotation.item
   285→                                            if (cleanWord.isNotBlank()) {
   286→                                                viewModel.lookupWord(cleanWord)
   287→                                            }
   288→                                        }
   289→                                }
   290→                            )
   291→
   292→                            // Translation line (if bilingual)
   293→                            cue.translation?.let { trans ->
   294→                                Spacer(Modifier.height(4.dp))
   295→                                Text(trans, color = MaterialTheme.colorScheme.onSurfaceVariant,
   296→                                    style = MaterialTheme.typography.bodyMedium)
   297→                            }
   298→                        } else {
   299→                            Text(uiState.statusText, color = MaterialTheme.colorScheme.onSurfaceVariant)
   300→                        }
   301→
   302→                        // AI analyze button
   303→                        if (uiState.currentSentence.isNotBlank()) {
   304→                            Spacer(Modifier.height(8.dp))
   305→                            Row {
   306→                                TextButton(onClick = { viewModel.analyzeSentence() }) {
   307→                                    Icon(Icons.Default.Psychology, null, Modifier.size(16.dp))
   308→                                    Spacer(Modifier.width(4.dp))
   309→                                    Text("AI分析此句")
   310→                                }
   311→                            }
   312→                        }
   313→                    }
   314→                }
   315→
   316→                // Subtitle scroll list
   317→                LazyColumn(
   318→                    state = listState,
   319→                    modifier = Modifier.fillMaxWidth().weight(1f).padding(horizontal = 16.dp),
   320→                    verticalArrangement = Arrangement.spacedBy(2.dp)
   321→                ) {
   322→                    itemsIndexed(uiState.subtitles) { index, cue ->
   323→                        val isActive = index == uiState.currentCueIndex
   324→                        Surface(
   325→                            modifier = Modifier.fillMaxWidth()
   326→                                .clickable { exoPlayer.seekTo(cue.startMs); exoPlayer.play() },
   327→                            color = if (isActive) MaterialTheme.colorScheme.primaryContainer
   328→                                    else Color.Transparent,
   329→                            shape = MaterialTheme.shapes.small
   330→                        ) {
   331→                            Row(modifier = Modifier.padding(8.dp), verticalAlignment = Alignment.CenterVertically) {
   332→                                Text(
   333→                                    formatTime(cue.startMs),
   334→                                    color = MaterialTheme.colorScheme.primary,
   335→                                    style = MaterialTheme.typography.labelSmall,
   336→                                    modifier = Modifier.width(48.dp)
   337→                                )
   338→                                Text(
   339→                                    cue.text,
   340→                                    style = MaterialTheme.typography.bodyMedium,
   341→                                    fontWeight = if (isActive) FontWeight.Bold else FontWeight.Normal
   342→                                )
   343→                            }
   344→                        }
   345→                    }
   346→                }
   347→
   348→            } else {
   349→                // === Dictation Mode ===
   350→                DictationPanel(
   351→                    subtitle = uiState.subtitles.getOrNull(uiState.dictationIndex),
   352→                    onSpeak = { text -> viewModel.speak(text) },
   353→                    onNext = { viewModel.nextDictation() },
   354→                    onLookup = { word -> viewModel.lookupWord(word) }
   355→                )
