   384→@Composable
   385→fun WordCardPanel(
   386→    card: WordCardData,
   387→    onSpeak: () -> Unit,
   388→    onFavorite: () -> Unit,
   389→    onDismiss: () -> Unit
   390→) {
   391→    var isFavorited by remember { mutableStateOf(false) }
   392→
   393→    Card(
