   418→            Text(card.translation, style = MaterialTheme.typography.bodyLarge, color = MaterialTheme.colorScheme.primary)
   419→            if (card.definitions.isNotEmpty()) {
   420→                Spacer(Modifier.height(8.dp))
   421→                Text("📖 释义", style = MaterialTheme.typography.labelMedium)
   422→                card.definitions.forEach { def ->
   423→                    Text("${def.partOfSpeech} ${def.definition}", style = MaterialTheme.typography.bodySmall)
   424→                }
   425→            }
   426→            if (card.examples.isNotEmpty()) {
   427→                Spacer(Modifier.height(8.dp))
   428→                Text("💬 例句", style = MaterialTheme.typography.labelMedium)
   429→                card.examples.forEach { ex ->
   430→                    Text(ex, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
   431→                }
   432→            }
   433→        }
   434→    }
