   437→@Composable
   438→fun DictationPanel(
   439→    subtitle: SubtitleCue?,
   440→    onSpeak: (String) -> Unit,
   441→    onNext: () -> Unit,
   442→    onLookup: (String) -> Unit
   443→) {
   444→    if (subtitle == null) {
   445→        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
   446→            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
   447→        }
   448→        return
   449→    }
   450→
   451→    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
   452→    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
   453→    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
   454→    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
   455→
   456→    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
   457→        // Word input boxes
   458→        Card(modifier = Modifier.fillMaxWidth()) {
   459→            Column(modifier = Modifier.padding(16.dp)) {
   460→                Row(
   461→                    modifier = Modifier.fillMaxWidth(),
   462→                    horizontalArrangement = Arrangement.spacedBy(8.dp),
   463→                    verticalAlignment = Alignment.CenterVertically
   464→                ) {
   465→                    words.forEachIndexed { i, word ->
   466→                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
   467→                            OutlinedTextField(
   468→                                value = inputs[i],
   469→                                onValueChange = { inputs[i] = it },
   470→                                modifier = Modifier.width((word.length * 14 + 30).coerceAtLeast(60).dp),
   471→                                singleLine = true,
   472→                                isError = results[i] == "wrong",
   473→                                colors = OutlinedTextFieldDefaults.colors(
   474→                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
   475→                                )
   476→                            )
   477→                            if (results[i] == "wrong") {
   478→                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
   479→                            }
   480→                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
   481→                                Text("查词", style = MaterialTheme.typography.labelSmall)
   482→                            }
   483→                        }
   484→                    }
   485→                }
   486→            }
   487→        }
   488→
   489→        Spacer(Modifier.height(12.dp))
   490→
   491→        // Control buttons
   492→        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
   493→            Button(onClick = { onSpeak(subtitle.text) }) {
   494→                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
   495→                Spacer(Modifier.width(4.dp))
   496→                Text("朗读")
   497→            }
   498→            Button(onClick = {
   499→                answers.forEachIndexed { i, answer ->
   500→                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
   501→                }
   502→            }) {
   503→                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
   504→                Spacer(Modifier.width(4.dp))
   505→                Text("检查")
   506→            }
   507→            Button(onClick = {
   508→                inputs.indices.forEach { inputs[it] = "" }
   509→                results.indices.forEach { results[it] = "" }
   510→                onNext()
   511→            }) {
   512→                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
   513→                Spacer(Modifier.width(4.dp))
   514→                Text("下一句")
   515→            }
   516→        }
   517→    }
   518→}
   519→
   520→private fun formatTime(ms: Long): String {
   521→    val totalSec = ms / 1000
   522→    val m = totalSec / 60
   523→    val s = totalSec % 60
   524→    return "$m:${s.toString().padStart(2, '0')}"
   525→}
