   207→    /**
   208→     * 处理服务发送的进度更新
   209→     */
   210→    fun onTranscriptionProgress(segment: Int, total: Int, progress: Int, message: String, remaining: Long) {
   211→        val remainingText = if (remaining > 0) {
   212→            "剩余 ${formatRemainingTime(remaining)}"
   213→        } else {
   214→            ""
   215→        }
   216→        _uiState.update { it.copy(
   217→            transcribeSegment = segment,
   218→            transcribeTotalSegments = total,
   219→            transcribeProgress = progress,
   220→            transcribeRemainingSeconds = remaining,
   221→            statusText = if (total > 1) {
   222→                "分段转录: $segment/$total 段 ($progress%)\n$message\n$remainingText"
   223→            } else {
   224→                "$message\n$remainingText"
   225→            }
   226→        )}
   227→    }
