   232→    fun onTranscriptionCompleted(videoPath: String, success: Boolean, detectedLang: String, subtitleCount: Int, error: String?) {
   233→        if (success) {
   234→            // 重新加载字幕文件
   235→            loadSubtitles(videoPath, null)
   236→            // 自动切换 UI 语言到检测到的语言
   237→            if (detectedLang.isNotBlank()) {
   238→                val langCode = when (detectedLang.lowercase()) {
   239→                    "chinese", "zh" -> "zh"
   240→                    "english", "en" -> "en"
   241→                    "spanish", "es" -> "es"
   242→                    "french", "fr" -> "fr"
   243→                    "german", "de" -> "de"
   244→                    "italian", "it" -> "it"
   245→                    "portuguese", "pt" -> "pt"
   246→                    "russian", "ru" -> "ru"
   247→                    "japanese", "ja" -> "ja"
   248→                    "korean", "ko" -> "ko"
   249→                    "arabic", "ar" -> "ar"
   250→                    "hindi", "hi" -> "hi"
   251→                    "thai", "th" -> "th"
   252→                    "vietnamese", "vi" -> "vi"
   253→                    else -> "en"
   254→                }
   255→                _uiState.update { it.copy(currentLang = langCode) }
   256→            }
   257→        } else {
   258→            // 转录失败，恢复旧字幕
   259→            _uiState.update { it.copy(
   260→                isTranscribing = false,
   261→                transcribeSegment = 0,
   262→                transcribeTotalSegments = 0,
   263→                transcribeProgress = 0,
   264→                statusText = error ?: "❌ 转录失败",
