   368→    fun analyzeSentence() {
   369→        val sentence = _uiState.value.currentSentence
   370→        if (sentence.isBlank()) return
   371→        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }
   372→
   373→        viewModelScope.launch(Dispatchers.IO) {
