   375→            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
   376→            val config = aiConfigStore.config.first()
   377→            val prompt = """分析${langName}句子："$sentence"
   378→【翻译】中文翻译
   379→【语法】1-2个关键语法点
   380→【重点词汇】2-3个重要词汇及释义"""
   381→            val result = aiService.chat(config, prompt)
   382→            _uiState.update { it.copy(
   383→                isAnalyzing = false,
   384→                aiAnalysisResult = result ?: "AI未配置或请求失败，请在设置中配置API Key"
   385→            )}
   386→        }
