   394→    fun toggleFavorite(word: String, phonetic: String = "", translation: String = "") {
   395→        android.util.Log.d("PlayerViewModel", "toggleFavorite: word=$word, lang=${_uiState.value.currentLang}")
   396→        viewModelScope.launch {
