   415→    /** Dictation */
   416→    fun nextDictation() {
   417→        val nextIdx = (_uiState.value.dictationIndex + 1).coerceAtMost(_uiState.value.subtitles.size - 1)
   418→        _uiState.update { it.copy(dictationIndex = nextIdx) }
   419→    }
