   516→/**
   517→ * 下载进度卡片组件
   518→ */
   519→@Composable
   520→private fun DownloadProgressCard(
   521→    task: DownloadTask,
   522→    onCancel: () -> Unit,
   523→    formatFileSize: (Long) -> String,
   524→    formatSpeed: (Long) -> String,
   525→    formatRemainingTime: (Long) -> String,
   526→    getStatusText: (DownloadStatus) -> String
   527→) {
   528→    Card(
   529→        modifier = Modifier.fillMaxWidth(),
   530→        colors = CardDefaults.cardColors(
   531→            containerColor = when (task.status) {
   532→                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
   533→                DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.tertiaryContainer
   534→                else -> MaterialTheme.colorScheme.primaryContainer
   535→            }
   536→        )
   537→    ) {
   538→        Column(modifier = Modifier.padding(16.dp)) {
   539→            // 标题和状态
   540→            Row(
   541→                modifier = Modifier.fillMaxWidth(),
   542→                horizontalArrangement = Arrangement.SpaceBetween,
   543→                verticalAlignment = Alignment.CenterVertically
   544→            ) {
   545→                Column(Modifier.weight(1f)) {
   546→                    Text(
   547→                        task.title,
   548→                        style = MaterialTheme.typography.titleSmall,
   549→                        maxLines = 1,
   550→                        overflow = TextOverflow.Ellipsis
   551→                    )
   552→                    Text(
   553→                        getStatusText(task.status),
   554→                        style = MaterialTheme.typography.bodySmall,
   555→                        color = when (task.status) {
   556→                            DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.error
   557→                            DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.onTertiaryContainer
   558→                            else -> MaterialTheme.colorScheme.onPrimaryContainer
   559→                        }
   560→                    )
   561→                }
   562→
   563→                // 取消按钮
   564→                if (task.status == DownloadStatus.DOWNLOADING || task.status == DownloadStatus.FETCHING_INFO) {
   565→                    IconButton(onClick = onCancel) {
   566→                        Icon(Icons.Default.Close, "取消", tint = MaterialTheme.colorScheme.error)
   567→                    }
   568→                }
   569→            }
   570→
   571→            Spacer(Modifier.height(12.dp))
   572→
   573→            // 进度条
   574→            if (task.status == DownloadStatus.DOWNLOADING) {
   575→                Column {
   576→                    Row(
   577→                        modifier = Modifier.fillMaxWidth(),
   578→                        horizontalArrangement = Arrangement.SpaceBetween
   579→                    ) {
   580→                        Text(
   581→                            "${task.progress}%",
   582→                            style = MaterialTheme.typography.bodySmall
   583→                        )
   584→                        if (task.speed > 0) {
   585→                            Text(
   586→                                formatSpeed(task.speed),
   587→                                style = MaterialTheme.typography.bodySmall,
   588→                                color = MaterialTheme.colorScheme.primary
   589→                            )
   590→                        }
   591→                    }
   592→
   593→                    Spacer(Modifier.height(4.dp))
   594→
   595→                    LinearProgressIndicator(
   596→                        progress = { task.progress / 100f },
   597→                        modifier = Modifier.fillMaxWidth(),
   598→                        color = MaterialTheme.colorScheme.primary
   599→                    )
   600→
   601→                    // 文件大小和剩余时间
   602→                    if (task.totalBytes > 0) {
   603→                        Spacer(Modifier.height(4.dp))
   604→                        Row(
   605→                            modifier = Modifier.fillMaxWidth(),
   606→                            horizontalArrangement = Arrangement.SpaceBetween
   607→                        ) {
   608→                            Text(
   609→                                "${formatFileSize(task.bytesDownloaded)} / ${formatFileSize(task.totalBytes)}",
   610→                                style = MaterialTheme.typography.bodySmall,
   611→                                color = MaterialTheme.colorScheme.onPrimaryContainer
   612→                            )
   613→                            if (task.remainingTime > 0 && task.speed > 0) {
   614→                                Text(
   615→                                    "剩余 ${formatRemainingTime(task.remainingTime)}",
   616→                                    style = MaterialTheme.typography.bodySmall,
   617→                                    color = MaterialTheme.colorScheme.onPrimaryContainer
   618→                                )
   619→                            }
   620→                        }
   621→                    }
   622→                }
   623→            } else if (task.status == DownloadStatus.FETCHING_INFO) {
   624→                Row(
   625→                    modifier = Modifier.fillMaxWidth(),
   626→                    verticalAlignment = Alignment.CenterVertically
   627→                ) {
   628→                    CircularProgressIndicator(
   629→                        modifier = Modifier.size(20.dp),
   630→                        strokeWidth = 2.dp
   631→                    )
   632→                    Spacer(Modifier.width(8.dp))
   633→                    Text(
   634→                        "正在解析视频信息...",
   635→                        style = MaterialTheme.typography.bodySmall,
   636→                        color = MaterialTheme.colorScheme.onPrimaryContainer
   637→                    )
   638→                }
   639→            } else if (task.status == DownloadStatus.FAILED) {
   640→                Row(
   641→                    modifier = Modifier.fillMaxWidth(),
   642→                    verticalAlignment = Alignment.CenterVertically
   643→                ) {
   644→                    Icon(
   645→                        Icons.Default.Error,
   646→                        contentDescription = null,
   647→                        tint = MaterialTheme.colorScheme.error,
   648→                        modifier = Modifier.size(20.dp)
   649→                    )
   650→                    Spacer(Modifier.width(8.dp))
   651→                    Text(
   652→                        task.errorMessage ?: "下载失败",
   653→                        style = MaterialTheme.typography.bodySmall,
   654→                        color = MaterialTheme.colorScheme.error
   655→                    )
   656→                }
   657→            } else if (task.status == DownloadStatus.COMPLETED) {
   658→                Row(
   659→                    modifier = Modifier.fillMaxWidth(),
